package looping;

public class switchstatement {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int day=1;
		switch (day) {
		case 1:
			System.out.println("Sunday");
		break;
		case 2:
			System.out.println("Monday");
		break;
		default:System.out.println("not valid");
			

	}

}
}
